    bool isAllStars(string &S1, int i) {
        // Loop through each character from index 0 to i-1
        for (int j = 1; j <= i; j++) {
            // If any character is not '*', return false
            if (S1[j - 1] != '*')
                return false;
        }
        // If loop finishes, it means all characters were '*'
        return true;
